(() => {
    const hamburger = document.querySelector('.hamburger');
    const mobileMenu = document.querySelector('.mobile-menu');
    const mobileLinks = document.querySelectorAll('.mobile-link');
    const nav = document.querySelector('nav');

    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    const isMobile = window.matchMedia('(max-width: 768px)').matches;
    const enableHeavyEffects = !prefersReducedMotion && !isMobile;
    const particlesCount = 700;

    if (hamburger && mobileMenu) {
        const setMenuState = (isOpen) => {
            hamburger.classList.toggle('active', isOpen);
            mobileMenu.classList.toggle('active', isOpen);
            hamburger.setAttribute('aria-expanded', String(isOpen));
        };

        hamburger.addEventListener('click', () => {
            const isOpen = !mobileMenu.classList.contains('active');
            setMenuState(isOpen);
        });

        mobileLinks.forEach((link) => {
            link.addEventListener('click', () => setMenuState(false));
        });

        document.addEventListener('keydown', (event) => {
            if (event.key === 'Escape') setMenuState(false);
        });
    }

    if (nav) {
        window.addEventListener('scroll', () => {
            nav.classList.toggle('scrolled', window.scrollY > 50);
        }, { passive: true });
    }

    if (enableHeavyEffects) {
        const cursor = document.querySelector('.cursor');
        const cursorDot = document.querySelector('.cursor-dot');
        const hoverTargets = document.querySelectorAll('.hover-target');

        if (cursor && cursorDot) {
            document.body.classList.add('custom-cursor');
            document.addEventListener('mousemove', (e) => {
                cursorDot.style.left = `${e.clientX}px`;
                cursorDot.style.top = `${e.clientY}px`;

                setTimeout(() => {
                    cursor.style.left = `${e.clientX}px`;
                    cursor.style.top = `${e.clientY}px`;
                }, 50);
            });

            hoverTargets.forEach((target) => {
                target.addEventListener('mouseenter', () => cursor.classList.add('hovered'));
                target.addEventListener('mouseleave', () => cursor.classList.remove('hovered'));
            });
        } else {
            document.body.classList.remove('custom-cursor');
        }
    }

    let torusKnot = null;
    let camera = null;

    if (enableHeavyEffects && window.THREE) {
        const container = document.getElementById('canvas-container');
        if (container) {
            const scene = new THREE.Scene();
            camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
            const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });

            renderer.setSize(window.innerWidth, window.innerHeight);
            container.appendChild(renderer.domElement);

            const geometry = new THREE.TorusKnotGeometry(10, 3, 100, 16);
            const material = new THREE.MeshBasicMaterial({
                color: 0x00f3ff,
                wireframe: true,
                transparent: true,
                opacity: 0.15,
            });
            torusKnot = new THREE.Mesh(geometry, material);
            scene.add(torusKnot);

            const particlesGeometry = new THREE.BufferGeometry();
            const posArray = new Float32Array(particlesCount * 3);

            for (let i = 0; i < particlesCount * 3; i++) {
                posArray[i] = (Math.random() - 0.5) * 50;
            }

            particlesGeometry.setAttribute('position', new THREE.BufferAttribute(posArray, 3));
            const particlesMaterial = new THREE.PointsMaterial({
                size: 0.05,
                color: 0xbc13fe,
                transparent: true,
                opacity: 0.8,
            });
            const particlesMesh = new THREE.Points(particlesGeometry, particlesMaterial);
            scene.add(particlesMesh);

            camera.position.z = 30;

            const clock = new THREE.Clock();
            const animate = () => {
                const elapsedTime = clock.getElapsedTime();
                torusKnot.rotation.y = elapsedTime * 0.1;
                particlesMesh.rotation.y = elapsedTime * 0.05;
                particlesMesh.rotation.x = elapsedTime * -0.02;

                renderer.render(scene, camera);
                requestAnimationFrame(animate);
            };
            animate();

            window.addEventListener('resize', () => {
                if (!camera) return;
                camera.aspect = window.innerWidth / window.innerHeight;
                camera.updateProjectionMatrix();
                renderer.setSize(window.innerWidth, window.innerHeight);
            });
        }
    }

    if (!prefersReducedMotion && window.gsap && window.ScrollTrigger) {
        gsap.registerPlugin(ScrollTrigger);

        const sections = document.querySelectorAll('section');
        sections.forEach((section) => {
            gsap.fromTo(
                section,
                { opacity: 0, y: 50 },
                {
                    opacity: 1,
                    y: 0,
                    duration: 1,
                    scrollTrigger: {
                        trigger: section,
                        start: 'top 80%',
                        end: 'bottom 20%',
                        toggleActions: 'play none none reverse',
                    },
                },
            );
        });

        if (enableHeavyEffects && torusKnot && camera) {
            gsap.to(torusKnot.rotation, {
                x: 3,
                z: 2,
                scrollTrigger: {
                    trigger: 'body',
                    start: 'top top',
                    end: 'bottom bottom',
                    scrub: 1,
                },
            });

            gsap.to(camera.position, {
                z: 15,
                y: -5,
                scrollTrigger: {
                    trigger: 'body',
                    start: 'top top',
                    end: 'bottom bottom',
                    scrub: 1,
                },
            });
        }
    }

    if (window.Typewriter) {
        new Typewriter('#typing-text', {
            strings: ['Intelligent Systems.', 'Scalable Web Apps.', 'Robotics Solutions.', 'AI-Powered Tools.'],
            autoStart: true,
            loop: true,
            cursor: '|',
            delay: 50,
            deleteSpeed: 30,
        });
    }

    if (window.VanillaTilt && !prefersReducedMotion) {
        VanillaTilt.init(document.querySelectorAll('.project-card'), {
            max: 8,
            speed: 400,
            glare: true,
            'max-glare': 0.2,
            scale: 1.02,
        });
    }
})();
